const e = $input.item.json;
const ourEmail = 'YOUR_BOOKED4US_EMAIL';
const from = e.from?.text || e.from?.value?.[0]?.address || '';
if (from.includes(ourEmail)) return [];
const subj = e.subject || '';
const refMatch = subj.match(/REF#([A-Z0-9]+)/i);
return [{ json: {
  messageId: (e.headers?.['message-id'] || e.messageId || '').replace(/[<>]/g,''),
  inReplyTo: (e.headers?.['in-reply-to'] || e.inReplyTo || '').replace(/[<>]/g,''),
  subjectSessionId: refMatch ? refMatch[1] : null,
  fromEmail: from,
  fromName: e.from?.value?.[0]?.name || from,
  subject: subj.replace(/^(Re:|Fwd:)\s*/i,'').trim(),
  body: e.text || e.html || '',
  receivedAt: new Date().toISOString()
}}];

const email = $('Parse Email').first().json;
const sessions = $input.all().map(i => i.json);
let session = null;
if (email.inReplyTo) session = sessions.find(s => s.last_sent_message_id === email.inReplyTo);
if (!session && email.subjectSessionId) session = sessions.find(s => s.session_id === email.subjectSessionId);
return [{ json: { email, session: session || null, sessionFound: !!session } }];

const resp = $input.first().json.content
const email = $('Prepare Triage Request').item.json.email;
let triage;
try {
  const clean = (resp || '{}').replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/, '').trim();
  triage = JSON.parse(clean);
} catch(e) {
  triage = { sufficient: false, assignee: 'info', gathered: {}, missing_info: [], clarification_questions: '' };
}
return [{ json: { email, triage } }];

const CALENDAR_MAP = { "dori":1, agi:2, zsuzsi:5, farkas_arpad:3, sukei_zsuzsi:4 };
const NAME_MAP = { dori:'Sipos Dóra', agi:'Lugosi Ágnes', zsuzsi:'Panykó-Tóth Zsuzsanna', farkas_arpad:'Farkas Árpád', sukei_zsuzsi:'Sükei Zsuzsa' };
const prev = $('Parse Triage Response').first().json;
const { email, triage } = prev;
const assignee = triage.assignee || 'dori';
const calendarId = CALENDAR_MAP[assignee] || 1;
const calendarName = NAME_MAP[assignee] || assignee;
return [{ json: { email, triage, calendarId, calendarName: calendarName } }];

const raw = $input.all().map(i => i.json);
const prev = $('Resolve Calendar (New)').first().json;
const { email, triage, calendarId, calendarName } = prev;
const list = Array.isArray(raw) ? raw : (raw[0]?.Data ? raw.map(i=>i.Data).flat() : []);
const services = list.filter(s => s && s.Id);
const service = services[0] || { Id: 1, Name: 'Gyógytorna' };
return [{ json: { email, triage, calendarId, calendarName, serviceId: service.Id, serviceName: service.Name } }];

