const resp = $input.item.json;
const prev = $('Select Service (New)').item.json;
const { email, calendarId, calendarName, serviceId } = prev;
const intervals = resp.Data?.Intervals || [];
const slots = [];
for (const day of intervals) {
  for (const slot of (day.Intervals || [])) {
    slots.push({ date: day.Date, start: slot.Start, end: slot.End, calendarId, calendarName, serviceId, datetime: `${day.Date}T${slot.Start}` });
    if (slots.length >= 8) break;
  }
  if (slots.length >= 8) break;
}
if (!slots.length) return [{ json: { ...prev, slots: [], emailBody: 'Sajnos jelenleg nincs szabad időpont. Kérem vegye fel velünk a kapcsolatot telefonon (+36708045493).', noSlots: true } }];
let body = 'Kedves Páciensünk!\n\nAz alábbi időpontok közül kérem válasszon (válaszolja meg e-mailen a sorszámot):\n\n';
slots.forEach((s,i) => { body += `${i+1}. ${s.date} ${s.start.slice(0,5)} — ${s.end.slice(0,5)}\n`; });
body += '\nVálaszában kérem adja meg a választott időpont sorszámát és telefonszámát a foglaláshoz: pl. "2, +36301234567"\n\nÜdvözlettel,\nFiziotars csapata';
return [{ json: { ...prev, slots, emailBody: body, noSlots: false } }];

const { email, triage } = $input.item.json;
const sessionId = Math.random().toString(36).slice(2,10).toUpperCase();
