const { email, session } = $input.item.json;
let slots = [];
try { slots = JSON.parse(session.offered_slots || '[]'); } catch(e) {}
const body = email.body || '';
const match = body.match(/\b([1-8])\b/);
const choice = match ? parseInt(match[1]) : null;
const chosenSlot = (choice && slots[choice-1]) ? slots[choice-1] : null;
const phoneMatch = body.match(/(?:\+36|06)[\s\-]?\d{1,2}[\s\-]?\d{3}[\s\-]?\d{4}|\+\d{10,12}/);
const phone = phoneMatch ? phoneMatch[0].replace(/[\s\-]/g, '') : '';
return [{ json: { email, session, slots, choice, chosenSlot, validChoice: !!chosenSlot, phone } }];

